const content =
  typeof $json.data === 'string'
    ? $json.data
    : (typeof $json.body === 'string'
        ? $json.body
        : (typeof $json.content === 'string' ? $json.content : ''));

// Change this node name if your upstream preparation node has a different name
const upstream = $('Rewrite URLs').item.json;

const fileName = String(upstream.desiredFileName || 'output.md');
const targetDir = String(upstream.targetDir || '/data/supportns-md');
const filePath = `${targetDir}/${fileName}`;

return {
  json: {
    targetDir,
    desiredFileName: fileName,
    targetPath: filePath
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(content, 'utf8'),
      fileName,
      'text/markdown'
    )
  }
};

const input = $input.first().json.body;

function rewriteHost(url) {
  if (!url || typeof url !== 'string') return url;
  return url.replace(/^http:\/\/127\.0\.0\.1/, 'http://192.168.0.117');
}

function sanitiseBaseName(name) {
  return String(name || 'Recording')
    .replace(/[\\/:*?"<>|]/g, '-')
    .replace(/\s+/g, ' ')
    .replace(/[ .]+$/g, '')
    .trim();
}

function assetBaseName(name) {
  return String(name || '').split('/').pop() || '';
}

function shouldIgnoreMarkdownAsset(name) {
  const baseName = assetBaseName(name).toLowerCase();
  return (
    baseName === 'summary.md' ||
    baseName.startsWith('summary__auto_sum_note') ||
    baseName.startsWith('outline__outline__')
  );
}

function londonPartsFromMs(ms) {
  const dt = new Date(ms);
  const parts = new Intl.DateTimeFormat('en-GB', {
    timeZone: 'Europe/London',
    year: 'numeric',
    month: '2-digit',
  }).formatToParts(dt);

  const year = parts.find(p => p.type === 'year')?.value;
  const month = parts.find(p => p.type === 'month')?.value;

  return { year, month };
}

const { year, month } = londonPartsFromMs(input.recording.start_time_ms);
const baseName = sanitiseBaseName(input.recording.filename);
const targetRoot = `/data/supportns-md/${year}/${month}`;

const items = [];

// Main summary only once
items.push({
  json: {
    kind: 'downloadedMarkdown',
    sourceUrl: rewriteHost(input.http_urls.summary),
    targetDir: targetRoot,
    desiredFileName: `${baseName} - Summary.md`,
    recordingId: input.recording.id,
  }
});

// Markdown assets except filtered duplicates
for (const asset of input.http_urls.assets || []) {
  if (asset.type !== 'markdown') continue;
  if (shouldIgnoreMarkdownAsset(asset.name)) continue;

  const rawAssetName = assetBaseName(asset.name);

  const safeAssetName = String(asset.name)
    .replace(/[\\/:*?"<>|]/g, '-')
    .replace(/[ .]+$/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  items.push({
    json: {
      kind: 'downloadedMarkdown',
      sourceUrl: rewriteHost(asset.url),
      targetDir: targetRoot,
      desiredFileName: /^speech_summary/i.test(rawAssetName) ? `${baseName} - Speech Summary.md` : `${baseName} - ${safeAssetName}`,
      recordingId: input.recording.id,
    }
  });
}

// Transcript generated from payload
items.push({
  json: {
    kind: 'generatedTranscript',
    targetDir: targetRoot,
    desiredFileName: `${baseName} - Transcript.md`,
    transcriptText: input.content?.transcript_text || '',
    recordingId: input.recording.id,
  }
});

return items;

function formatTranscript(text) {
  return String(text || '')
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/\s*(\[\d{2}:\d{2}(?::\d{2})?\])/g, '\n$1')
    .replace(/^\n+/, '')
    .trim() + '\n';
}

const formatted = formatTranscript($json.transcriptText);
const fileName = $json.desiredFileName;
const filePath = `${$json.targetDir}/${fileName}`;

return [
  {
    json: {
      targetDir: $json.targetDir,
      desiredFileName: fileName,
      targetPath: filePath,
    },
    binary: {
      data: await this.helpers.prepareBinaryData(
        Buffer.from(formatted, 'utf8'),
        fileName,
        'text/markdown'
      )
    }
  }
];
